using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_CreatesCorrectNotification()
    {
        // Act
        _sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "1050", EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 1050) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Department", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'Test' has been created", DisplayName = "CREATE message")]
    [DataRow(EntityOperation.UPDATE, "Student 'Test' has been updated", DisplayName = "UPDATE message")]
    [DataRow(EntityOperation.DELETE, "Student 'Test' has been deleted", DisplayName = "DELETE message")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(
        EntityOperation operation, string expectedMessage)
    {
        // Act
        _sut.SendNotification("Student", "1", "Test", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
        Assert.AreEqual(operation.ToString(), notification.Operation);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFOOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("A", first!.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("B", second!.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("C", third!.EntityType);

        // Queue should be empty now
        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        // No exception = pass
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        _sut.Dispose();
        _sut.Dispose();
        // No exception = pass
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_UsesIdFallback()
    {
        // Act
        _sut.SendNotification("Instructor", "7", null, EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 7) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
    {
        // Act
        _sut.SendNotification("Instructor", "7", "  ", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = System.DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);

        // Assert
        var after = System.DateTime.Now.AddSeconds(1);
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_EvenDivision_IsExact()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_SingleItem_IsOne()
    {
        var source = new[] { 1 }.AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);
        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void PageIndex_ReturnsCorrectValue()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPageOfMultiple_ReturnsTrue()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 10);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsPropertiesCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };
        var result = new PaginatedList<string>(items, 10, 2, 3);

        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SinglePageExactFit_NoPreviousOrNextPage()
    {
        var source = Enumerable.Range(1, 10).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    [DataRow(1, 5, 5, DisplayName = "Page 1, size 5 → 5 items")]
    [DataRow(2, 5, 5, DisplayName = "Page 2, size 5 → 5 items")]
    [DataRow(3, 5, 2, DisplayName = "Page 3, size 5 → 2 items")]
    public void Create_VariousPageSizes_ReturnsCorrectCount(int page, int pageSize, int expectedCount)
    {
        var source = Enumerable.Range(1, 12).AsQueryable();
        var result = PaginatedList<int>.Create(source, page, pageSize);
        Assert.AreEqual(expectedCount, result.Count);
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;

namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Helper to create in-memory SchoolContext instances for testing.
/// Each test gets a unique database name to ensure isolation.
/// </summary>
internal static class TestDbContextFactory
{
    public static SchoolContext Create(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    /// <summary>
    /// Seeds basic test data into the context.
    /// </summary>
    public static SchoolContext CreateWithSeedData(string? dbName = null)
    {
        var context = Create(dbName);

        // Add departments
        var engineering = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        var math = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 100000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        context.Departments.AddRange(engineering, math);

        // Add instructors
        var instructor1 = new Instructor
        {
            ID = 1,
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = new DateTime(1995, 3, 11)
        };
        var instructor2 = new Instructor
        {
            ID = 2,
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6)
        };
        context.Instructors.AddRange(instructor1, instructor2);

        // Add courses
        var chemistry = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };
        var calculus = new Course
        {
            CourseID = 1045,
            Title = "Calculus",
            Credits = 4,
            DepartmentID = 2
        };
        context.Courses.AddRange(chemistry, calculus);

        // Add students
        var student1 = new Student
        {
            ID = 1,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = new DateTime(2010, 9, 1)
        };
        var student2 = new Student
        {
            ID = 2,
            LastName = "Alonso",
            FirstMidName = "Meredith",
            EnrollmentDate = new DateTime(2012, 9, 1)
        };
        var student3 = new Student
        {
            ID = 3,
            LastName = "Anand",
            FirstMidName = "Arturo",
            EnrollmentDate = new DateTime(2013, 9, 1)
        };
        context.Students.AddRange(student1, student2, student3);

        // Add enrollments
        context.Enrollments.AddRange(
            new Enrollment { StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { StudentID = 2, CourseID = 1045, Grade = Grade.B }
        );

        // Add course assignments
        context.CourseAssignments.AddRange(
            new CourseAssignment { InstructorID = 1, CourseID = 1050 },
            new CourseAssignment { InstructorID = 2, CourseID = 1045 }
        );

        // Add office assignments
        context.OfficeAssignments.Add(
            new OfficeAssignment { InstructorID = 2, Location = "Smith 17" }
        );

        context.SaveChanges();
        return context;
    }
}

