namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateWithSeedData();
        _controller = new NotificationsController(_context);
        // Drain existing notifications
        var svc = new ContosoUniversity.Services.NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void GetNotifications_NoNotifications_ReturnsEmptySuccess()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        // The result is a JsonResult with an anonymous type
        var value = result.Value;
        Assert.IsNotNull(value);

        // Use reflection to check anonymous type properties
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.IsTrue((bool)successProp.GetValue(value)!);

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, (int)countProp.GetValue(value)!);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - add a notification through the service
        var svc = new ContosoUniversity.Services.NotificationService();
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsTrue((bool)successProp!.GetValue(value)!);

        var countProp = value.GetType().GetProperty("count");
        Assert.IsTrue((int)countProp!.GetValue(value)! >= 1);

        svc.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.IsTrue((bool)successProp.GetValue(value)!);
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - add more than 10 notifications
        var svc = new ContosoUniversity.Services.NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);

        var countProp = value!.GetType().GetProperty("count");
        // Should be capped at 10
        Assert.IsTrue((int)countProp!.GetValue(value)! <= 10);

        svc.Dispose();
    }
}

