namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Helper to create in-memory SchoolContext instances for testing.
/// Each test gets a unique database name to ensure isolation.
/// </summary>
internal static class TestDbContextFactory
{
    public static SchoolContext Create(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    /// <summary>
    /// Seeds basic test data into the context.
    /// Does NOT set explicit IDs for auto-generated keys (Person.ID).
    /// Returns a SeedData object with references to seeded entities.
    /// </summary>
    public static (SchoolContext Context, SeedData Data) CreateWithSeedData(string? dbName = null)
    {
        var context = Create(dbName);

        // Add departments (DepartmentID is auto-generated)
        var engineering = new Department
        {
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        var math = new Department
        {
            Name = "Mathematics",
            Budget = 100000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        context.Departments.AddRange(engineering, math);
        context.SaveChanges();

        // Add instructors (ID is auto-generated from Person)
        var instructor1 = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = new DateTime(1995, 3, 11),
            CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        // Add courses (CourseID is NOT auto-generated - DatabaseGeneratedOption.None)
        var chemistry = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = engineering.DepartmentID
        };
        var calculus = new Course
        {
            CourseID = 1045,
            Title = "Calculus",
            Credits = 4,
            DepartmentID = math.DepartmentID
        };
        context.Courses.AddRange(chemistry, calculus);
        context.SaveChanges();

        // Add students (ID is auto-generated from Person)
        var student1 = new Student
        {
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = new DateTime(2010, 9, 1)
        };
        var student2 = new Student
        {
            LastName = "Alonso",
            FirstMidName = "Meredith",
            EnrollmentDate = new DateTime(2012, 9, 1)
        };
        var student3 = new Student
        {
            LastName = "Anand",
            FirstMidName = "Arturo",
            EnrollmentDate = new DateTime(2013, 9, 1)
        };
        context.Students.AddRange(student1, student2, student3);
        context.SaveChanges();

        // Add enrollments
        context.Enrollments.AddRange(
            new Enrollment { StudentID = student1.ID, CourseID = 1050, Grade = Grade.A },
            new Enrollment { StudentID = student2.ID, CourseID = 1045, Grade = Grade.B }
        );
        context.SaveChanges();

        // Add course assignments
        context.CourseAssignments.AddRange(
            new CourseAssignment { InstructorID = instructor1.ID, CourseID = 1050 },
            new CourseAssignment { InstructorID = instructor2.ID, CourseID = 1045 }
        );
        context.SaveChanges();

        // Add office assignments
        context.OfficeAssignments.Add(
            new OfficeAssignment { InstructorID = instructor2.ID, Location = "Smith 17" }
        );
        context.SaveChanges();

        var data = new SeedData
        {
            Student1 = student1,
            Student2 = student2,
            Student3 = student3,
            Instructor1 = instructor1,
            Instructor2 = instructor2,
            Engineering = engineering,
            Math = math,
            Chemistry = chemistry,
            Calculus = calculus
        };

        return (context, data);
    }
}

internal sealed class SeedData
{
    public Student Student1 { get; set; } = null!;
    public Student Student2 { get; set; } = null!;
    public Student Student3 { get; set; } = null!;
    public Instructor Instructor1 { get; set; } = null!;
    public Instructor Instructor2 { get; set; } = null!;
    public Department Engineering { get; set; } = null!;
    public Department Math { get; set; } = null!;
    public Course Chemistry { get; set; } = null!;
    public Course Calculus { get; set; } = null!;
}

